// Devuelve UN ITEM POR CADA PDF encontrado en el email
function findAllPDFs(parts, depth) {
  if (!Array.isArray(parts) || depth > 10) return [];
  let pdfs = [];
  for (const part of parts) {
    const mime = (part.mimeType || '').toLowerCase();
    const filename = (part.filename || '');
    const hasAttach = !!(part.body && part.body.attachmentId);
    const size = (part.body && part.body.size) || 0;
    if (hasAttach && size > 0) {
      const isPdf = mime.includes('pdf') || filename.toLowerCase().endsWith('.pdf');
      if (isPdf) {
        pdfs.push({ attachmentId: part.body.attachmentId, filename: filename || 'factura.pdf' });
      }
    }
    if (part.parts) {
      pdfs = pdfs.concat(findAllPDFs(part.parts, depth + 1));
    }
  }
  return pdfs;
}

const payload = $json.payload || {};
const headers = (payload.headers || []).reduce((a, h) => ({ ...a, [h.name.toLowerCase()]: h.value }), {});
const emailMeta = {
  email_gmail_id:  $json.id,
  email_from:      headers.from    || '',
  email_subject:   headers.subject || '',
  email_date:      $json.internalDate || new Date().toISOString(),
  email_messageId: $json.id
};

const pdfs = findAllPDFs(payload.parts || [], 0);

if (pdfs.length === 0) {
  const tree = JSON.stringify((payload.parts || []).map(function m(p) {
    return { mime: p.mimeType, file: p.filename || '', hasId: !!(p.body && p.body.attachmentId), sub: (p.parts || []).map(m) };
  }));
  throw new Error('Sin adjuntos PDF encontrados. Arbol: ' + tree);
}

return pdfs.map(pdf => ({
  json: {
    messageId:    $json.id,
    attachmentId: pdf.attachmentId,
    pdf_filename: pdf.filename,
    ...emailMeta
  }
}));

// Convierte base64url de Gmail API a $binary para Extract From File
const meta = $('Extraer metadata adjunto').item.json;
const base64url = $json.data || '';

if (!base64url) throw new Error('Gmail API no devolvio datos del adjunto');

const base64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
const buffer = Buffer.from(base64, 'base64');

const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  meta.pdf_filename,
  'application/pdf'
);

return [{
  json: {
    pdf_binary_key:  'data',
    pdf_filename:    meta.pdf_filename,
    email_gmail_id:  meta.email_gmail_id,
    email_from:      meta.email_from,
    email_subject:   meta.email_subject,
    email_date:      meta.email_date,
    email_messageId: meta.email_messageId
  },
  binary: { data: binaryData }
}];

const rawText = $json.text || $json.content || '';

let hash;
try {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(rawText));
  hash = Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
} catch(e) {
  let h = 5381;
  for (let i = 0; i < rawText.length; i++) h = (((h << 5) + h) + rawText.charCodeAt(i)) & 0xffffffff;
  hash = (h >>> 0).toString(16).padStart(8, '0') + rawText.length.toString(16);
}

return [{ json: {
  pdf_text:        rawText,
  pdf_filename:    $json.pdf_filename,
  pdf_hash:        hash,
  email_gmail_id:  $json.email_gmail_id,
  email_from:      $json.email_from,
  email_subject:   $json.email_subject,
  email_date:      $json.email_date,
  email_messageId: $json.email_messageId,
  fuente:          'EMAIL_GMAIL_N8N'
}}];

// -- NODO 10: Normalizar campos OpenAI -> staging_facturas --
const prevNode = $('Preparar prompt OpenAI').item.json;

// Extraer el contenido JSON de la respuesta del AI Agent
let rawContent = '';
if (typeof $json.output === 'string' && $json.output.trim().startsWith('{')) {
  rawContent = $json.output;
} else if ($json.message && $json.message.content) {
  rawContent = $json.message.content;
} else if ($json.choices && $json.choices[0] && $json.choices[0].message) {
  rawContent = $json.choices[0].message.content;
} else if (typeof $json.output === 'string') {
  rawContent = $json.output;
} else if (typeof $json.content === 'string') {
  rawContent = $json.content;
} else {
  rawContent = JSON.stringify($json);
}

// Parsear JSON de OpenAI (strip markdown si viene envuelto)
let parsed;
try {
  const clean = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  const m = rawContent.match(/\{[\s\S]+\}/);
  if (m) {
    try { parsed = JSON.parse(m[0]); } catch(e2) {
      throw new Error('No se pudo parsear JSON de OpenAI: ' + e.message + ' | Raw: ' + rawContent.substring(0, 500));
    }
  } else {
    throw new Error('Respuesta OpenAI no contiene JSON valido: ' + rawContent.substring(0, 300));
  }
}


// Normalizar fecha: acepta YYYY-MM-DD o DD/MM/YYYY → devuelve YYYY-MM-DD o null
function parseDate(d) {
  if (!d) return null;
  const s = String(d).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;                          // YYYY-MM-DD
  const a = s.match(/^(\d{2})[\/\-](\d{2})[\/\-](\d{4})$/);
  if (a) return `${a[3]}-${a[2]}-${a[1]}`;                                 // DD/MM/YYYY o DD-MM-YYYY
  const b = s.match(/^(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
  if (b) return `${b[1]}-${b[2]}-${b[3]}`;                                 // YYYY/MM/DD
  return null;
}

// Helpers SQL
const esc = s => s ? String(s).replace(/'/g, "''") : null;
const str = (s, nullable = true) => (s !== null && s !== undefined && s !== '') ? `'${esc(s)}'` : (nullable ? 'NULL' : "''");
const numF = n => (n !== null && n !== undefined && !isNaN(n)) ? parseFloat(n) : 0;

// Mapeo de campos
